        if (q[i] !== q[q.length - 1 - i]) {
            isPalindrome = false;
            break;
        }
    }

    // Calculate sum of elements
    let sum = q.reduce((acc, val) => acc + val, 0);

    // Return true if balanced (palindrome) and sum <= w
    return isPalindrome && sum <= w;
}
