function is_simple_power(x, n) {
    // Handle edge cases
    if (x === 1) {
        return true; // n^0 = 1 for any n != 0
    }

    if (n === 0) {
        return false; // 0^k is either 0 or undefined, never equals x unless x=0 and k>0, but let's be careful
    }

    if (n === 1) {
        return x === 1; // 1^k = 1 for any k >= 0
    }

    if (x === 0) {
        return n !== 0 && n !== 1; // Actually, 0 is not a simple power in the usual sense unless we consider 0^k=0
        // But typically "simple power" implies positive integers. Let's assume x > 0 and n > 1 for simplicity.
    }

    // For negative bases or non-integer exponents, we need to be careful.
    // The problem likely assumes positive integers.
    if (n < 0) {
        // If n is negative, powers alternate sign. We can still check by repeated multiplication/division.
    }

    // Let's use a loop approach: repeatedly divide x by n and check if we reach 1.
    let current = x;

    // Handle the case where n might be negative
    if (n === -1) {
        return x === 1 || x === -1;
    }

    while (current !== 1 && current !== -1) {
        if (current % n !== 0) {
            return false;
        }
        current = current / n;
    }

    return current === 1 || current === -1;
}
