function starts_one_ends(n) {
    if (n === 0) return 0;
    if (n === 1) return 1; // Only the number "1"

    // Numbers that start with 1: 1xx...x (n-1 digits remaining, each can be 0-9)
    // Count = 10^(n-1)
    const startsWithOne = Math.pow(10, n - 1);

    // Numbers that end with 1: xx...x1 (n-1 digits before the last, first digit 1-9, others 0-9)
    // First digit: 1-9 (9 choices), middle n-2 digits: 0-9 (10 choices each), last digit: 1 (1 choice)
    // Count = 9 * 10^(n-2)
    const endsWithOne = 9 * Math.pow(10, n - 2);

    // Numbers that both start and end with 1: 1xx...x1
    // First digit: 1 (1 choice), middle n-2 digits: 0-9 (10 choices each), last digit: 1 (1 choice)
    // Count = 10^(n-2)
    const bothStartAndEndWithOne = Math.pow(10, n - 2);

    // Use inclusion-exclusion principle
    return startsWithOne + endsWithOne - bothStartAndEndWithOne;
}
