function encrypt(s) {
    // The shift is 2 * 2 = 4 places down the alphabet
    const shift = 4;
    let result = '';

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        // Check if it's a lowercase letter
        if (char >= 'a' && char <= 'z') {
            // Shift the character by 'shift' positions, wrapping around the alphabet
            const shifted = ((char.charCodeAt(0) - 97 + shift) % 26) + 97;
            result += String.fromCharCode(shifted);
        } else if (char >= 'A' && char <= 'Z') {
            // Shift uppercase letters similarly
            const shifted = ((char.charCodeAt(0) - 65 + shift) % 26) + 65;
            result += String.fromCharCode(shifted);
        } else {
            // Non-alphabetic characters remain unchanged
            result += char;
        }
    }

    return result;
}
