function encode(message) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U']);

    return message.split('').map(char => {
        let result = char;

        // Swap case
        if (char >= 'a' && char <= 'z') {
            result = char.toUpperCase();
        } else if (char >= 'A' && char <= 'Z') {
            result = char.toLowerCase();
        }

        // Replace vowels with the letter 2 places ahead in the alphabet
        const lowerChar = result.toLowerCase();
        if (vowels.has(lowerChar)) {
            let code = result.charCodeAt(0);
            // Determine if original was uppercase or lowercase to maintain case after shift
            const isUpper = result >= 'A' && result <= 'Z';

            // Shift by 2 in the alphabet, wrapping around z->a or Z->A if needed
            let newCode;
            if (isUpper) {
                newCode = ((code - 65 + 2) % 26) + 65;
            } else {
                newCode = ((code - 97 + 2) % 26) + 97;
            }
            result = String.fromCharCode(newCode);
        }

        return result;
    }).join('');
}
