```javascript
function move_one_ball(arr) {
    if (arr.length === 0 || arr.length === 1) {
        return true;
    }

    // Count the number of "drops" where arr[i] > arr[i+1]
    let drops = 0;
    const n = arr.length;

    for (let i = 0; i < n; i++) {
        if (arr[i] > arr[(i + 1) % n]) {
            drops++;
        }
        // If more than one drop, it can't be sorted by rotation
        if (drops > 1) {
            return false;
        }
    }

    // If there are no drops, the array is already sorted.
    // If there is exactly one drop, we need to check if rotating at that point gives a sorted array.
    // Actually, if drops == 0, it's already sorted -> true.
    // If drops == 1, let's find where the drop is and verify the rotated array is sorted.

    if (drops === 0) {
        return true;
    }

    // Find the index where arr[i] > arr[i+1]
    let dropIndex = -1;
    for (let i = 0; i < n; i++) {
        if (arr[i] > arr[(i + 1) % n]) {
            dropIndex = i;
            break;
        }
    }

    // The sorted array should start from dropIndex + 1
    // Check if the array is non-decreasing when rotated to start at dropIndex + 1
    const start = (dropIndex + 1) % n;
    for (let i = 0; i < n - 1; i++) {
        const currIdx = (start + i) % n;
        const nextIdx = (start + i + 1) % n;
        if (arr[currIdx] > arr[nextIdx]) {
            return false;
        }
    }

    return true;
}
