    for (let i = 0; i < grid.length; i++) {
        // Count the number of water units in this well
        let waterUnits = grid[i].reduce((sum, unit) => sum + unit, 0);

        // Calculate how many bucket drops are needed for this well
        if (capacity > 0) {
            totalDrops += Math.ceil(waterUnits / capacity);
