function sort_array(arr) {
    // Helper function to count the number of ones in binary representation
    const countOnes = (num) => {
        let count = 0;
        while (num > 0) {
            count += num & 1;
            num >>= 1;
        }
        return count;
    };

    // Sort the array based on the number of ones in binary representation,
    // and then by decimal value for ties.
    return arr.sort((a, b) => {
        const onesA = countOnes(a);
        const onesB = countOnes(b);
        if (onesA !== onesB) {
            return onesA - onesB;
        }
        return a - b;
    });
}
