function match_parens(lst) {
    // Function to calculate the balance of a string
    // Returns the minimum prefix balance and the final balance
    function getBalanceInfo(s) {
        let minPrefix = 0;
        let current = 0;
        for (let char of s) {
            if (char === '(') {
                current++;
            } else {
                current--;
            }
            if (current < minPrefix) {
                minPrefix = current;
            }
        }
        return { minPrefix, finalBalance: current };
    }

    // Check if two strings can be concatenated in order a+b to form a balanced string
    function canConcatenate(a, b) {
        const infoA = getBalanceInfo(a);
        const infoB = getBalanceInfo(b);

        // When concatenating a + b:
        // The minimum prefix balance of the combined string is min(infoA.minPrefix, infoA.finalBalance + infoB.minPrefix)
        // The final balance must be 0
        // And at no point should the balance drop below 0

        const combinedMinPrefix = Math.min(infoA.minPrefix, infoA.finalBalance + infoB.minPrefix);
        const combinedFinalBalance = infoA.finalBalance + infoB.finalBalance;

        return combinedFinalBalance === 0 && combinedMinPrefix >= 0;
    }

    // Try both orders: lst[0] + lst[1] and lst[1] + lst[0]
    if (canConcatenate(lst[0], lst[1]) || canConcatenate(lst[1], lst[0])) {
        return "Yes";
    }

    return "No";
}
