function valid_date(date) {
    // Rule 1: The date string is not empty.
    if (!date || typeof date !== 'string' || date.trim() === '') {
        return false;
    }

    // Check format: mm-dd-yyyy
    const parts = date.split('-');
    if (parts.length !== 3) {
        return false;
    }

    const monthStr = parts[0];
    const dayStr = parts[1];
    const yearStr = parts[2];

    // Check that each part is exactly the right length for mm, dd, yyyy
    if (monthStr.length !== 2 || dayStr.length !== 2 || yearStr.length !== 4) {
        return false;
    }

    // Parse integers
    const month = parseInt(monthStr, 10);
    const day = parseInt(dayStr, 10);
    const year = parseInt(yearStr, 10);

    // Check if parsing resulted in NaN or if the string had non-numeric characters
    if (isNaN(month) || isNaN(day) || isNaN(year)) {
        return false;
    }

    // Rule 3: The months should not be less than 1 or higher than 12.
    if (month < 1 || month > 12) {
        return false;
    }

    // Determine the maximum days for the given month
    let maxDays;
    switch (month) {
        case 1:
        case 3:
        case 5:
        case 7:
        case 8:
        case 10:
        case 12:
            maxDays = 31;
            break;
        case 4:
        case 6:
        case 9:
        case 11:
            maxDays = 30;
            break;
        case 2:
            // Check for leap year
            const isLeapYear = (year % 4 === 0 && year % 100 !== 0) || (year % 400 === 0);
            maxDays = isLeapYear ? 29 : 28;
            break;
        default:
            return false; // Should not happen due to month check above
    }

    // Rule 2: The number of days is valid for the given month
    if (day < 1 || day > maxDays) {
        return false;
    }

    return true;
}
