function minPath(grid, k) {
    const n = grid.length;

    // We need to find the lexicographically smallest path of length k.
    // Since we want the lexicographically smallest sequence, we should try to pick the smallest possible value at each step.
    // This is similar to a BFS/Dijkstra-like approach but for lexicographic order.

    // Let's use a priority queue (min-heap) based on the path sequence built so far.
    // However, storing full paths in the heap can be expensive.
    // Instead, we can think of it as: at each step, we want to extend the current set of candidate paths 
    // by choosing the next cell that gives the lexicographically smallest extension.

    // Actually, since we want the globally lexicographically smallest path, we can use a BFS-like approach:
    // Step 0: All cells are candidates. We pick the cell with the smallest value as the start.
    // But wait, there might be multiple cells with small values. We need to consider all paths that could potentially be minimal.

    // A better approach: Use a priority queue where each element is (path_sequence_so_far, current_cell).
    // But path sequences can be long and comparing them is expensive.

    // Alternative insight: The lexicographically smallest path of length k can be found by greedily choosing the 
    // smallest next value at each step, but we must ensure that such a choice is part of SOME valid path of length k.

    // Let's use dynamic programming or BFS with state (step, row, col) and track the best path to reach that state.
    // However, "best" here is lexicographic order of the entire path, not just the last element.

    // Since k can be large, we need an efficient approach.
    // Let's think about it differently: We want to minimize the sequence lexicographically.
    // This means we want the first element to be as small as possible. If there are ties, we want the second element 
    // to be as small as possible, and so on.

    // So, let's find all cells with the minimum value in the grid. Let this set be S_1.
    // Then, from each cell in S_1, we look at all neighbors. We want to pick the neighbor(s) with the smallest value.
    // Let the minimum value among all neighbors of all cells in S_1 be v_2. Let S_2 be the set of cells with value v_2 
    // that are neighbors of some cell in S_1.
    // Then, from each cell in S_2, we look at all neighbors (including possibly going back). We want to pick the neighbor(s) 
    // with the smallest value. Let this be v_3, and so on.

    // This is essentially a BFS where at each step, we expand all cells that are part of some lexicographically minimal path prefix.

    // Algorithm:
    // 1. Find the minimum value in the grid, say min_val. Collect all cells (r, c) with grid[r][c] == min_val into a set current_cells.
    // 2. For step from 2 to k:
    //    a. Find the minimum value among all neighbors of all cells in current_cells. Let this be next_min_val.
    //    b. Collect all neighbor cells (nr, nc) such that grid[nr][nc] == next_min_val and (nr, nc) is adjacent to some cell in current_cells. 
    //       But wait, we need to be careful: a cell might be reachable from multiple cells in current_cells. We just need it to be reachable from at least one.
    //    c. Set current_cells = the set of these neighbor cells.
    // 3. The path is formed by the sequence of values: [min_val, next_min_val for step 2, ...]

    // However, there's a subtlety: when we collect neighbors, we need to make sure that we're building a valid path. 
    // Since we're only tracking the set of possible current positions for lexicographically minimal paths, this should work.

    // Let's implement this step by step.

    // Helper function to get neighbors
    const getNeighbors = (r, c) => {
        const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];
        const neighbors = [];
        for (const [dr, dc] of dirs) {
            const nr = r + dr;
            const nc = c + dc;
            if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
                neighbors.push([nr, nc]);
            }
        }
        return neighbors;
    };

    // Step 1: Find all cells with the minimum value
    let minVal = Infinity;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] < minVal) {
                minVal = grid[i][j];
            }
        }
    }

    let currentCells = new Set();
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === minVal) {
                currentCells.add(`${i},${j}`);
            }
        }
    }

    const path = [minVal];

    // Steps 2 to k
    for (let step = 1; step < k; step++) {
        let nextMinVal = Infinity;

        // Find the minimum value among all neighbors of current cells
        for (const cellStr of currentCells) {
            const [r, c] = cellStr.split(',').map(Number);
            const neighbors = getNeighbors(r, c);
            for (const [nr, nc] of neighbors) {
                if (grid[nr][nc] < nextMinVal) {
                    nextMinVal = grid[nr][nc];
                }
            }
        }

        path.push(nextMinVal);

        // Collect all neighbor cells with value == nextMinVal that are adjacent to some cell in currentCells
        const nextCells = new Set();
        for (const cellStr of currentCells) {
            const [r, c] = cellStr.split(',').map(Number);
            const neighbors = getNeighbors(r, c);
            for (const [nr, nc] of neighbors) {
                if (grid[nr][nc] === nextMinVal) {
                    nextCells.add(`${nr},${nc}`);
                }
            }
        }

        currentCells = nextCells;
    }

    return path;
}
