function is_nested(string) {
    let depth = 0;
    let maxDepth = 0;

    for (let i = 0; i < string.length; i++) {
        if (string[i] === '[') {
            depth++;
            maxDepth = Math.max(maxDepth, depth);
        } else if (string[i] === ']') {
            depth--;
            if (depth < 0) {
                // Invalid bracket sequence, reset
                depth = 0;
                maxDepth = 0;
            }
        }
