function special_factorial(n) {
    // Calculate factorial of a number
    function factorial(num) {
        if (num <= 1) return 1;
        let result = 1;
        for (let i = 2; i <= num; i++) {
            result *= i;
        }
        return result;
    }

    // Calculate Brazilian factorial: n! * (n-1)! * ... * 1!
    let product = 1;
    for (let i = n; i >= 1; i--) {
        product *= factorial(i);
    }

    return product;
}
