    // Check if it starts with a letter from the latin alphabet
    const firstChar = namePart[0];
    if (!/^[a-zA-Z]$/.test(firstChar)) {
        return 'No';
    }

    // Check if the extension is one of ['txt', 'exe', 'dll']
    if (extPart !== 'txt' && extPart !== 'exe' && extPart !== 'dll') {
        return 'No';
    }

    // Count digits in the entire file name
    let digitCount = 0;
    for (let i = 0; i < file_name.length; i++) {
        if (file_name[i] >= '0' && file_name[i] <= '9') {
            digitCount++;
        }
    }

    // There should not be more than three digits
    if (digitCount > 3) {
        return 'No';
    }

    return 'Yes';
