        if (i % 3 === 0 && i % 4 !== 0) {
            // Multiple of 3 but not 4: square it
            sum += lst[i] * lst[i];
        } else if (i % 4 === 0) {
            // Multiple of 4 (which includes multiples of 12, but we need to check priority)
            // Actually, let's re-read: "cube the integer entry if its index is a multiple of 4 and not a multiple of 3"
            // So if index is multiple of 4 AND not multiple of 3, cube it.
