function order_by_points(nums) {
    // Helper function to calculate the sum of digits of a number
    const digitSum = (num) => {
        // Convert number to string, remove negative sign, split into digits, and sum them
        return Math.abs(num).toString().split('').reduce((sum, digit) => sum + parseInt(digit), 0);
    };

    // Create an array of objects with value, original index, and digit sum
    const indexedNums = nums.map((num, index) => ({
        value: num,
        index: index,
        sum: digitSum(num)
    }));

    // Sort based on digit sum (ascending), then by original index (ascending) for ties
    indexedNums.sort((a, b) => {
        if (a.sum !== b.sum) {
            return a.sum - b.sum;
        }
        return a.index - b.index;
    });

    // Extract the sorted values
    return indexedNums.map(item => item.value);
}
