function get_max_triples(n) {
    // Generate the array a where a[i] = i*i - i + 1 for i from 1 to n
    const a = [];
    for (let i = 1; i <= n; i++) {
        a.push(i * i - i + 1);
    }

    // Count triples (i, j, k) with i < j < k such that a[i] + a[j] + a[k] is divisible by 3
    let count = 0;

    // We can optimize by considering remainders modulo 3
    // Let's count how many elements have remainder 0, 1, or 2 when divided by 3
    const remCount = [0, 0, 0]; // remCount[r] = number of elements with a[i] % 3 == r

    for (let i = 0; i < n; i++) {
        const rem = a[i] % 3;
        remCount[rem]++;
    }

    // A triple (a[i], a[j], a[k]) has sum divisible by 3 if:
    // rem_i + rem_j + rem_k ≡ 0 (mod 3)
    // Possible combinations of remainders:
    // (0, 0, 0): C(remCount[0], 3)
    // (1, 1, 1): C(remCount[1], 3)
    // (2, 2, 2): C(remCount[2], 3)
    // (0, 1, 2): remCount[0] * remCount[1] * remCount[2]

    function combinations(n, k) {
        if (k < 0 || k > n) return 0;
        if (k === 0 || k === n) return 1;
        if (k === 1) return n;
        // For small k, compute directly
        let result = 1;
        for (let i = 0; i < k; i++) {
            result = result * (n - i) / (i + 1);
        }
        return Math.round(result);
    }

    const triples = combinations(remCount[0], 3) + 
                    combinations(remCount[1], 3) + 
                    combinations(remCount[2], 3) + 
                    remCount[0] * remCount[1] * remCount[2];

    return triples;
}
