            // Right associative: evaluate from right to left, but since we're scanning left to right,
            // we need to handle consecutive ** carefully. Actually, for simplicity and correctness with
            // standard JS Math.pow which is right-associative, let's do a loop that finds the rightmost ** first?
            // Standard approach: find all **, evaluate them. Since ** is right-associative, 
            // a[0] ** a[1] ** a[2] = a[0] ** (a[1] ** a[2])
            // Let's handle this by scanning from right to left for ** operators.
            break;
        }
        i++;
    }

    // Actually, let's use a more robust approach: two-pass or stack-based evaluation.
    // Given the small size and specific operators, let's do multiple passes for each precedence level.

    // Pass 1: Exponentiation (right-associative)
    // To handle right-associativity correctly with multiple **, we process from right to left.
    let idx = ops.length - 1;
    while (idx >= 0) {
        if (ops[idx] === '**') {
            vals[idx] = Math.pow(vals[idx], vals[idx + 1]);
            ops.splice(idx, 1);
            vals.splice(idx + 1, 1);
        }
        idx--;
    }

    // Pass 2: Multiplication and Floor Division (left-associative)
    idx = 0;
    while (idx < ops.length) {
        if (ops[idx] === '*' || ops[idx] === '//') {
            if (ops[idx] === '*') {
                vals[idx] = vals[idx] * vals[idx + 1];
            } else {
                // Floor division: Math.trunc for negative numbers? The problem says non-negative integers.
                // But floor division of positive numbers is just integer division.
                // In JS, Math.floor(a / b) works for positive numbers.
                vals[idx] = Math.floor(vals[idx] / vals[idx + 1]);
            }
            ops.splice(idx, 1);
            vals.splice(idx + 1, 1);
        } else {
            idx++;
        }
    }

    // Pass 3: Addition and Subtraction (left-associative)
    idx = 0;
    while (idx < ops.length) {
        if (ops[idx] === '+' || ops[idx] === '-') {
            if (ops[idx] === '+') {
                vals[idx] = vals[idx] + vals[idx + 1];
            } else {
                vals[idx] = vals[idx] - vals[idx + 1];
