function get_max_triples(n) {
  let counts = [0, 0, 0];
  for (let i = 1; i <= n; i++) {
    let val = (i * i - i + 1) % 3;
    // Ensure positive modulo result for JavaScript
    counts[((val % 3) + 3) % 3]++;
  }

  let triples = 0;

  // Case 1: All three elements have the same remainder modulo 3
  // (0,0,0), (1,1,1), (2,2,2)
  for (let i = 0; i < 3; i++) {
    if (counts[i] >= 3) {
      triples += (counts[i] * (counts[i] - 1) * (counts[i] - 2)) / 6;
    }
  }

  // Case 2: Each element has a different remainder modulo 3
  // (0,1,2) -> 0 + 1 + 2 = 3, which is a multiple of 3
  triples += counts[0] * counts[1] * counts[2];

  return triples;
}
