function starts_one_ends(n) {
  if (n <= 0) return 0;
  if (n === 1) return 1;

  // Total n-digit numbers is 9 * 10^(n-1)
  // Numbers starting with 1: 1 * 10^(n-1)
  // Numbers ending with 1: 9 * 10^(n-2) (since the first digit cannot be 0)
  // Intersection (starting with 1 AND ending with 1): 1 * 10^(n-2)

  // Formula: Count(Starts1) + Count(Ends1) - Count(Starts1 AND Ends1)
  // Count = 10^(n-1) + 9 * 10^(n-2) - 10^(n-2)
  // Count = 10^(n-1) + 8 * 10^(n-2)

  // Using BigInt to handle potential large values of n
  const nBig = BigInt(n);
  const term1 = 10n ** (nBig - 1n);
  const term2 = 8n * (10n ** (nBig - 2n));

  return Number(term1 + term2);
}
