function histogram(test) {
  if (!test.trim()) {
    return {};
  }

  const counts = {};
  const letters = test.split(/\s+/);
  let maxCount = 0;

  for (const char of letters) {
    if (char === "") continue;
    counts[char] = (counts[char] || 0) + 1;
    if (counts[char] > maxCount) {
      maxCount = counts[char];
    }
  }

  const result = {};
  for (const key in counts) {
    if (counts[key] === maxCount) {
      result[key] = maxCount;
    }
  }

  return result;
}
