function is_nested(string) {
  let count = 0;
  let max_depth = 0;
  let current_depth = 0;

  for (let i = 0; i < string.length; i++) {
    if (string[i] === '[') {
      current_depth++;
      if (current_depth > max_depth) {
        max_depth = current_depth;
      }
    } else if (string[i] === ']') {
      current_depth--;
    }

    // If depth becomes negative, we reset for the sake of checking 
    // potential valid subsequences, though the problem asks for a valid subsequence.
    // A valid nested subsequence exists if there's a part of the string 
    // where we can form "[[]]".
    // This is equivalent to checking if there is a '[' followed by another '['
    // and then two ']' such that the nesting is valid.
  }

  // Simplified logic for the requirement: 
  // A string contains a nested subsequence if and only if 
  // it contains the pattern "[[]]" as a subsequence.
  // This means we need to find '[', then another '[', then ']', then another ']'
  // in that specific relative order.

  let state = 0;
  for (let char of string) {
    if (state === 0 && char === '[') {
      state = 1;
    } else if (state === 1 && char === '[') {
      state = 2;
    } else if (state === 2 && char === ']') {
      state = 3;
    } else if (state === 3 && char === ']') {
      state = 4;
    }
  }

