function get_max_triples(n) {
  let counts = [0, 0, 0];

  for (let i = 1; i <= n; i++) {
    let val = i * i - i + 1;
    counts[val % 3]++;
  }

  let triples = 0;

  // Case 1: All three have the same remainder modulo 3
  // (r + r + r) % 3 == (3r) % 3 == 0
  for (let i = 0; i < 3; i++) {
    let count = counts[i];
    if (count >= 3) {
      triples += (count * (count - 1) * (count - 2)) / 6;
    }
  }

  // Case 2: All three have different remainders modulo 3
  // (0 + 1 + 2) % 3 == 3 % 3 == 0
  triples += counts[0] * counts[1] * counts[2];

  return triples;
}
