function do_algebra(operator, operand) {
  const expression = [];
  for (let i = 0; i < operand.length; i++) {
    expression.push(operand[i]);
    if (i < operator.length) {
      let op = operator[i];
      // Handle floor division symbol conversion for JS eval
      if (op === '//') {
        op = '/';
      }
      expression.push(op);
    }
  }

  // To handle floor division // correctly in an expression context,
  // we cannot simply use eval because JS uses / for float division.
  // We must implement the order of operations manually or parse carefully.
  // However, the problem implies standard mathematical precedence.

  // Step 1: Handle Exponentiation (**)
  let i = 0;
  while (i < operator.length) {
    if (operator[i] === '**') {
      operand[i] = Math.pow(operand[i], operand[i + 1]);
      operand.splice(i + 1, 1);
      operator.splice(i, 1);
    } else {
      i++;
    }
  }

  // Step 2: Handle Multiplication (*) and Floor Division (//)
  i = 0;
  while (i < operator.length) {
    if (operator[i] === '*' || operator[i] === '//') {
      let res;
      if (operator[i] === '*') {
        res = operand[i] * operand[i + 1];
      } else {
        res = Math.floor(operand[i] / operand[i + 1]);
      }
      operand[i] = res;
      operand.splice(i + 1, 1);
      operator.splice(i, 1);
    } else {
      i++;
    }
  }

  // Step 3: Handle Addition (+) and Subtraction (-)
  i = 0;
  while (i < operator.length) {
    if (operator[i] === '+' || operator[i] === '-') {
      let res;
      if (operator[i] === '+') {
        res = operand[i] + operand[i + 1];
      } else {
        res = operand[i] - operand[i + 1];
      }
      operand[i] = res;
      operand.splice(i + 1, 1);
      operator.splice(i, 1);
    } else {
      i++;
    }
  }

  return operand[0];
}
