  let minDiff = Infinity;
  let closestPair = [0, 0];

  for (let i = 0; i < sorted.length - 1; i++) {
    const diff = sorted[i + 1] - sorted[i];
    if (diff < minDiff) {
      minDiff = diff;
      closestPair = [sorted[i], sorted[i + 1]];
    }
  }

  return closestPair;
}
