  const digits = x.toString().split('');
  const n = digits.length;

  if (shift > n) {
    return digits.reverse().join('');
  }

  const effectiveShift = shift % n;
  if (effectiveShift === 0) return digits.join('');

  const rightPart = digits.slice(n - effectiveShift);
  const leftPart = digits.slice(0, n - effectiveShift);

  return rightPart.concat(leftPart).join('');
}
