    return [...array];
  }

  const first = array[0];
  const last = array[array.length - 1];
  const isAscending = (first + last) % 2 !== 0;

  const sortedArray = [...array].sort((a, b) => {
    if (isAscending) {
      return a - b;
    } else {
      return b - a;
    }
  });

