function check_dict_case(dict) {
  const keys = Object.keys(dict);
  if (keys.length === 0) return false;

  let allLower = true;
  let allUpper = true;

  for (let key of keys) {
    if (typeof key !== 'string') {
      return false;
    }

    if (key !== key.toLowerCase()) {
      allLower = false;
    }
    if (key !== key.toUpperCase()) {
      allUpper = false;
    }

    // If it's neither all lower nor all upper, we can't return true
    if (!allLower && !allUpper) return false;
  }

  return allLower || allUpper;
}
