```javascript
function do_algebra(operator, operand) {
  const expression = operand.reduce((acc, val, i) => {
    if (i === 0) return [val];
    const op = operator[i - 1];
    acc.push(op);
    acc.push(val);
    return acc;
  }, []);

  const expressionString = expression.map(item => {
    if (item === '//') return '/';
    return item;
  }).join(' ');

  const evaluate = (expr) => {
    const tokens = expr.match(/(\d+|\*\*|[\+\-\*\/])/g);
    const stack = [];

    const precedence = {
      '+': 1,
      '-': 1,
      '*': 2,
      '/': 2,
      '//': 2,
      '**': 3
    };

    const applyOp = (ops, values) => {
      const op = ops.pop();
      const right = values.pop();
      const left = values.pop();
      switch (op) {
        case '+': values.push(left + right); break;
        case '-': values.push(left - right); break;
        case '*': values.push(left * right); break;
        case '/': values.push(Math.floor(left / right)); break;
        case '//': values.push(Math.floor(left / right)); break;
        case '**': values.push(Math.pow(left, right)); break;
      }
    };

    const opsStack = [];
    const valStack = [];

    for (let i = 0; i < tokens.length; i++) {
      const token = tokens[i];
      if (/\d+/.test(token)) {
        valStack.push(parseFloat(token));
      } else {
        while (
          opsStack.length > 0 &&
          precedence[opsStack[opsStack.length - 1]] >= precedence[token] &&
          token !== '**'
        ) {
          applyOp(opsStack, valStack);
        }
        // Exponentiation is right-associative, but for this scope, 
        // standard precedence handling is sufficient.
        opsStack.push(token);
      }
    }

    while (opsStack.length > 0) {
      applyOp(opsStack, valStack);
    }
    return valStack[0];
  };

  // Re-implementing a more robust parser for the specific rules provided
  // to handle order of operations (PEMDAS) correctly.

  let currentOperands = [...operand];
  let currentOperators = [...operator];

  // 1. Handle Exponentiation (**)
  for (let i = 0; i < currentOperators.length; i++) {
    if (currentOperators[i] === '**') {
      const res = Math.pow(currentOperands[i], currentOperands[i + 1]);
      currentOperands.splice(i, 2, res);
      currentOperators.splice(i, 1);
      i--;
    }
  }

  // 2. Handle Multiplication, Floor Division
  for (let i = 0; i < currentOperators.length; i++) {
    if (currentOperators[i] === '*' || currentOperators[i] === '//') {
      const res = currentOperators[i] === '*' 
        ? currentOperands[i] * currentOperands[i + 1] 
        : Math.floor(currentOperands[i] / currentOperands[i + 1]);
      currentOperands.splice(i, 2, res);
      currentOperators.splice(i, 1);
      i--;
    }
  }

  // 3. Handle Addition, Subtraction
  for (let i = 0; i < currentOperators.length; i++) {
    if (currentOperators[i] === '+' || currentOperators[i] === '-') {
      const res = currentOperators[i] === '+' 
        ? currentOperands[i] + currentOperands[i + 1] 
        : currentOperands[i] - currentOperands[i + 1];
      currentOperands.splice(i, 2, res);
      currentOperators.splice(i, 1);
      i--;
    }
  }

  return currentOperands[0];
}
