function starts_one_ends(n) {
  if (n <= 0) return 0;
  if (n === 1) return 1;

  // Total n-digit numbers: 10^(n-1) * 9 (from 10^(n-1) to 10^n - 1)
  // Numbers starting with 1: 10^(n-1)
  // Numbers ending with 1: 9 * 10^(n-2)
  // Numbers starting and ending with 1: 10^(n-2)

  // Using BigInt to handle potentially large n
  const powerNminus1 = BigInt(10) ** BigInt(n - 1);
  const powerNminus2 = BigInt(10) ** BigInt(n - 2);

  const startsWith1 = powerNminus1;
  const endsWith1 = BigInt(9) * powerNminus2;
  const both = powerNminus2;

  return Number(startsWith1 + endsWith1 - both);
}
