```javascript
function largest_smallest_integers(lst) {
  let largest_neg = -Infinity;
  let smallest_pos = Infinity;
  let found_neg = false;
  let found_pos = false;

  for (let i = 0; i < lst.length; i++) {
    if (lst[i] < 0) {
      if (lst[i] > largest_neg) {
        largest_neg = lst[i];
      }
      found_neg = true;
    } else if (lst[i] > 0) {
      if (lst[i] < smallest_pos) {
        smallest_pos = lst[i];
      }
      found_pos = true;
    }
  }

  return [
    found_neg ? largest_neg : undefined,
    found_pos ? smallest_pos : undefined
  ];
}
```

```javascript
function compare_one(a, b) {
  const parse = (val) => {
    if (typeof val === 'number') return val;
    if (typeof val === 'string') {
      const sanitized = val.replace(',', '.');
      const num = parseFloat(sanitized);
      return isNaN(num) ? null : num;
    }
    return null;
  };

  const numA = parse(a);
  const numB = parse(b);

  if (numA === null || numB === null) return undefined;
  if (numA === numB) return undefined;

  return numA > numB ? a : b;
}
```

```javascript
function is_equal_to_sum_even(n) {
  // The smallest sum of 4 positive even numbers is 2 + 2 + 2 + 2 = 8.
  // For n to be a sum of even numbers, n must itself be even.
  // If n is even and n >= 8, it can always be written as 2 + 2 + 2 + (n - 6).
  // Since n is even and n >= 8, n - 6 is an even number >= 2.
  return n >= 8 && n % 2 === 0;
}
