function special_factorial(n) {
  let totalProduct = 1n;
  let currentFactorial = 1n;

  for (let i = 1; i <= n; i++) {
    currentFactorial *= BigInt(i);
    totalProduct *= currentFactorial;
  }

  return Number(totalProduct);
}
