```javascript
function do_algebra(operator, operand) {
  const expression = operand.reduce((acc, curr, idx) => {
    if (idx === 0) return curr.toString();
    const op = operator[idx - 1];
    // Replace // with a representation that behaves like floor division
    // However, standard JS eval uses / for float division. 
    // We'll handle operators manually or transform the string.
    return `${acc} ${op} ${curr}`;
  }, "");

  // To handle // correctly in JS, we can't just use eval on "//" 
  // because it's a comment. Let's use a custom parser approach.

  // Step 1: Convert operators to tokens and handle precedence manually 
  // or use a safer approach by transforming the expression into a valid JS expression.
  // Since // is floor division, we can replace 'x // y' with 'Math.floor(x / y)'
  // But precedence of // and ** matters. 

  // A more robust way:
  // 1. Build a list of operands and operators.
  // 2. Handle ** (Right associative, highest precedence)
  // 3. Handle * and // (Left associative, middle precedence)
  // 4. Handle + and - (Left associative, lowest precedence)

  let tokens = [];
  for (let i = 0; i < operand.length; i++) {
    tokens.push(operand[i]);
    if (i < operator.length) {
      tokens.push(operator[i]);
    }
  }

  // Step 1: Exponentiation (**) - Right to left
  for (let i = tokens.length - 1; i >= 0; i--) {
    if (tokens[i] === '**') {
      const left = tokens[i - 1];
      const right = tokens[i + 1];
      const result = Math.pow(left, right);
      tokens.splice(i - 1, 3, result);
      i--;
    }
  }

  // Step 2: Multiplication (*) and Floor Division (//) - Left to right
  for (let i = 0; i < tokens.length; i++) {
    if (tokens[i] === '*' || tokens[i] === '//') {
      const left = tokens[i - 1];
      const right = tokens[i + 1];
      const result = tokens[i] === '*' ? left * right : Math.floor(left / right);
      tokens.splice(i - 1, 3, result);
      i--;
    }
  }

  // Step 3: Addition (+) and Subtraction (-) - Left to right
  for (let i = 0; i < tokens.length; i++) {
    if (tokens[i] === '+' || tokens[i] === '-') {
      const left = tokens[i - 1];
      const right = tokens[i + 1];
      const result = tokens[i] === '+' ? left + right : left - right;
      tokens.splice(i - 1, 3, result);
      i--;
    }
  }

  return tokens[0];
}
