```javascript
function move_one_ball(arr) {
  if (arr.length <= 1) {
    return true;
  }

  let breaks = 0;
  let n = arr.length;

  for (let i = 0; i < n; i++) {
    if (arr[i] > arr[(i + 1) % n]) {
      breaks++;
    }
  }

  // A sorted array that has been rotated will have at most one point 
  // where the next element is smaller than the current element.
  // Because elements are unique, if it is a rotated sorted array,
  // there is exactly one index i where arr[i] > arr[i+1], 
  // and specifically arr[n-1] must be less than arr[0] if a rotation occurred.
  // However, the condition "breaks <= 1" covers both the already sorted 
  // (0 breaks) and the rotated sorted (1 break) cases.
  return breaks <= 1;
}
