```javascript
function valid_date(date) {
  if (!date || typeof date !== 'string') {
    return false;
  }

  const parts = date.split('-');
  if (parts.length !== 3) {
    return false;
  }

  const monthStr = parts[0];
  const dayStr = parts[1];
  const yearStr = parts[2];

  // Check if parts are exactly two digits for mm and dd, and four for yyyy
  if (monthStr.length !== 2 || dayStr.length !== 2 || yearStr.length !== 4) {
    return false;
  }

  // Check if all parts are numeric
  if (!/^\d+$/.test(monthStr) || !/^\d+$/.test(dayStr) || !/^\d+$/.test(yearStr)) {
    return false;
  }

  const month = parseInt(monthStr, 10);
  const day = parseInt(dayStr, 10);
  const year = parseInt(yearStr, 10);

  if (month < 1 || month > 12) {
    return false;
  }

  let maxDays;
  switch (month) {
    case 1:
    case 3:
    case 5:
    case 7:
    case 8:
    case 10:
    case 12:
      maxDays = 31;
      break;
    case 4:
    case 6:
    case 9:
    case 11:
      maxDays = 30;
      break;
    case 2:
      // Check for leap year
      if ((year % 4 === 0 && year % 100 !== 0) || (year % 400 === 0)) {
        maxDays = 29;
      } else {
        maxDays = 28;
      }
      break;
    default:
      return false;
  }

  return day >= 1 && day <= maxDays;
}
