function intersection(interval1, interval2) {
  const start = Math.max(interval1[0], interval2[0]);
  const end = Math.min(interval1[1], interval2[1]);

  if (start >= end) {
    return "NO";
  }

  // The length of the intersection of closed intervals [a, b] and [c, d] is end - start.
  // However, the example (1, 3) and (2, 4) results in (2, 3), length 3-2 = 1.
  // The example (-3, -1) and (-5, 5) results in (-3, -1), length -1 - (-3) = 2.
  // 2 is prime, so we return "YES".
  const length = end - start;

  if (length < 2) return "NO";

  for (let i = 2, s = Math.sqrt(length); i <= s; i++) {
    if (length % i === 0) return "NO";
  }

  return "YES";
}
