function minPath(grid, k) {
  const n = grid.length;
  let minVal = Infinity;
  let startPos = null;

  // Find the smallest value in the grid to start the path
  for (let r = 0; r < n; r++) {
    for (let c = 0; c < n; c++) {
      if (grid[r][c] < minVal) {
        minVal = grid[r][c];
        startPos = [r, c];
      }
    }
  }

  // Since we want the lexicographically smallest path, we always want 
  // the first element to be as small as possible.
  // The second element must be a neighbor of the first.
  // To keep the sequence lexicographically smallest, after picking the 
  // minimum element, we should move to its smallest neighbor.
  // However, if we move to a neighbor and then need to continue the path,
  // we might want to move back to the minimum element to keep subsequent 
  // values small.

  // Let's analyze: 
  // A path is [v1, v2, v3, ..., vk].
  // To minimize lexicographically, we first minimize v1.
  // Then we minimize v2 (must be neighbor of v1).
  // Then we minimize v3 (must be neighbor of v2).

  // Step 1: Find the smallest value in the grid.
  // Step 2: Find its smallest neighbor.
  // Step 3: If k > 2, the best strategy is to toggle between 
  // the smallest value and its smallest neighbor.
  // Example: grid=[[1,2],[3,4]], k=3. 
  // Possible paths from 1: [1,2,1], [1,2,4]. [1,2,1] is smaller.
  // Example: grid=[[1,5],[6,2]], k=3.
  // Possible paths from 1: [1,5,1], [1,5,2], [1,5,6].
  // Wait, if we start at 1, the neighbor is 5. From 5 we can go to 1 or 6.
  // [1, 5, 1] is the lexicographically smallest.

  let bestPath = null;

  // We must iterate through all possible starting cells to be safe, 
  // although the smallest value is the most likely candidate.
  // But wait, the smallest value might have a neighbor that is very large,
  // while a slightly larger value might have a neighbor that is very small.
  // Actually, lexicographical comparison prioritizes the FIRST element.
  // So we MUST start at the global minimum.

  const [startR, startC] = startPos;
  const dr = [-1, 1, 0, 0];
  const dc = [0, 0, -1, 1];

  let currentR = startR;
  let currentC = startC;
  const path = [grid[startR][startC]];

  if (k === 1) return path;

  // For the second element, we must pick the smallest neighbor of the minimum.
  let minNeighborVal = Infinity;
  let minNeighborPos = null;

  for (let i = 0; i < 4; i++) {
    const nr = startR + dr[i];
    const nc = startC + dc[i];
    if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
      if (grid[nr][nc] < minNeighborVal) {
        minNeighborVal = grid[nr][nc];
        minNeighborPos = [nr, nc];
      }
    }
  }

  path.push(minNeighborVal);

  // For the rest of the elements (k >= 3), to keep it lexicographically smallest,
  // we should aim to pick the smallest possible neighbor at each step.
  // Since we can revisit cells, if we are at a neighbor of the minimum, 
  // we can immediately jump back to the minimum.
  // Any value we pick after the second element will be at least the minimum.
  // By returning to the minimum, we ensure the 3rd, 4th... elements are as small as possible.

  let currR = minNeighborPos[0];
  let currC = minNeighborPos[1];

  for (let i = 2; i < k; i++) {
    // Current value is grid[currR][currC]. 
    // We want to pick the smallest neighbor of (currR, currC).
    let bestNextVal = Infinity;
    let bestNextPos = null;
    for (let j = 0; j < 4; j++) {
      const nr = currR + dr[j];
      const nc = currC + dc[j];
      if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
        if (grid[nr][nc] < bestNextVal) {
          bestNextVal = grid[nr][nc];
          bestNextPos = [nr, nc];
        }
      }
    }
    path.push(bestNextVal);
    currR = bestNextPos[0];
    currC = bestNextPos[1];
  }

  return path;
}

