  const result = new Array(n + 1);
  // The sequence index starts from 0. Based on the problem:
  // tri(1) = 3
  // tri(2) = 1 + 2/2 = 2
  // tri(3) = tri(2) + tri(1) + tri(4)
  // This implies we need tri(4) to calculate tri(3).
  // This is a circular dependency unless we determine the pattern or calculate values in specific order.
  // Let's re-examine the requirements.
  // tri(1) = 3
  // tri(2) = 2
  // tri(4) = 1 + 4/2 = 3
  // tri(3) = tri(2) + tri(1) + tri(4) = 2 + 3 + 3 = 8
  // The examples say tri(3) returns [1, 3, 2, 8].
  // This maps to: index 0 = 1, index 1 = 3, index 2 = 2, index 3 = 8.
  // So result[0] is 1, result[1] is 3, result[2] is 2, result[3] is 8.

  result[0] = 1; // Based on example result[0]
  if (n >= 1) result[1] = 3;
  if (n >= 2) result[2] = 2;
  if (n >= 3) result[3] = 8;

  // To solve for higher n, we need to know the pattern for odd n.
  // tri(n) = tri(n-1) + tri(n-2) + tri(n+1) (for n odd)
  // For n odd: tri(n+1) = tri(n) - tri(n-1) - tri(n-2)
  // But if n+1 is even, tri(n+1) = 1 + (n+1)/2.
  // Let's check if the formula holds:
  // tri(3) = tri(2) + tri(1) + tri(4)
  // tri(4) is even, so tri(4) = 1 + 4/2 = 3.
  // tri(3) = 2 + 3 + 3 = 8. Correct.
  // Now find tri(5): 5 is odd.
  // tri(5) = tri(4) + tri(3) + tri(6)
  // tri(6) = 1 + 6/2 = 4
  // tri(5) = 3 + 8 + 4 = 15.
  // Now find tri(7): 7 is odd.
  // tri(7) = tri(6) + tri(5) + tri(8)
  // tri(8) = 1 + 8/2 = 5
  // tri(7) = 4 + 15 + 5 = 24.

  for (let i = 4; i <= n; i++) {
    if (i % 2 === 0) {
      result[i] = 1 + i / 2;
    } else {
      // tri(i) = tri(i-1) + tri(i-2) + tri(i+1)
      // We know tri(i+1) because i+1 is even.
      // tri(i+1) = 1 + (i+1)/2
      result[i] = result[i - 1] + result[i - 2] + (1 + (i + 1) / 2);
    }
  }

  return result.slice(0, n + 1);
}
