  let maxUniqueCount = -1;
  let result = "";

  for (const word of words) {
    const uniqueCount = new Set(word).size;

    if (uniqueCount > maxUniqueCount) {
      maxUniqueCount = uniqueCount;
      result = word;
    } else if (uniqueCount === maxUniqueCount) {
      if (word < result) {
