  // to be the smallest possible. If there's a tie (which there isn't here 
  // because values are unique), we'd look at the second element.
  // However, once we pick the smallest starting value, the next step must 
  // be to the smallest available neighbor.
  // But wait, the path can visit the same cell multiple times.
  // If we are at cell (r, c), the best next move is the neighbor with the 
  // minimum value. If that minimum neighbor is smaller than the current cell,
  // we might want to move back and forth.

  // Actually, the greedy approach works for lexicographical minimum:
  // Step 1: Start at the global minimum.
  // Step 2: From current cell, move to the neighbor with the smallest value.
  // BUT, there is a catch: what if moving to a slightly larger neighbor now
  // allows us to reach a much smaller neighbor in the next step?
  // Lexicographical order prioritizes the *earliest* difference.
  // So, the first element MUST be the minimum possible value in the grid.
  // The second element MUST be the minimum neighbor of that cell.
  // The third element MUST be the minimum neighbor of the second element, and so on.

  const dr = [-1, 1, 0, 0];
  const dc = [0, 0, -1, 1];

  let currentR = startR;
  let currentC = startC;
  const path = [grid[startR][startC]];

  for (let i = 1; i < k; i++) {
    let minNeighbor = Infinity;
    let nextR = -1;
    let nextC = -1;

    for (let j = 0; j < 4; j++) {
      const nr = currentR + dr[j];
      const nc = currentC + dc[j];

      if (nr >= 0 && nr < N && nc >= 0 && nc < N) {
        if (grid[nr][nc] < minNeighbor) {
          minNeighbor = grid[nr][nc];
          nextR = nr;
          nextC = nc;
        }
      }
    }

    // Because we can revisit cells, the greedy choice is always optimal for 
    // lexicographical order because the first difference determines the order.
    currentR = nextR;
    currentC = nextC;
    path.push(grid[currentR][currentC]);
  }

  return path;
}
